import{_ as e,a,b as n,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as d,o,c as r,a2 as h}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Thêm WebDAV Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/webdav.md","filePath":"vi-VN/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"vi-VN/upload/webdav.md"};function c(s,t,p,u,g,b){return o(),r("div",null,[...t[0]||(t[0]=[h('<h1 id="them-webdav-channel" tabindex="-1">Thêm WebDAV Channel <a class="header-anchor" href="#them-webdav-channel" aria-label="Permalink to &quot;Thêm WebDAV Channel&quot;">​</a></h1><h2 id="phu-hop-nhat-khi-nao" tabindex="-1">Phù hợp nhất khi nào <a class="header-anchor" href="#phu-hop-nhat-khi-nao" aria-label="Permalink to &quot;Phù hợp nhất khi nào&quot;">​</a></h2><p>Dùng WebDAV channel khi:</p><ul><li>Bạn có NAS, cloud drive hoặc object storage service cung cấp WebDAV endpoint.</li><li>Bạn muốn uploaded images được lưu trong WebDAV directory của riêng mình.</li><li>Bạn muốn credentials được lưu trong D1 <code>upload_channels</code> table thay vì expose lâu dài ở frontend.</li></ul><h2 id="can-chuan-bi-gi-truoc-khi-bat-đau" tabindex="-1">Cần chuẩn bị gì trước khi bắt đầu <a class="header-anchor" href="#can-chuan-bi-gi-truoc-khi-bat-đau" aria-label="Permalink to &quot;Cần chuẩn bị gì trước khi bắt đầu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Server-side WebDAV URL, ví dụ <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>Dùng để sign in vào WebDAV service.</td></tr><tr><td>Password</td><td>Dùng để sign in vào WebDAV service.</td></tr><tr><td>Authentication mode</td><td>Mặc định là <code>Basic</code>. Chỉ dùng <code>Digest</code> hoặc auto negotiation nếu server yêu cầu.</td></tr><tr><td>Storage directory</td><td>Directory dùng để lưu files. Mặc định là <code>imgbed</code>.</td></tr></tbody></table><h2 id="them-o-đau" tabindex="-1">Thêm ở đâu <a class="header-anchor" href="#them-o-đau" aria-label="Permalink to &quot;Thêm ở đâu&quot;">​</a></h2><ol><li>Mở System Settings.</li><li>Vào Upload Settings.</li><li>Nhấn Add Channel ở góc trên bên phải.</li><li>Chọn <code>WebDAV</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Tác dụng</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết cho WebDAV channel, ví dụ <code>koofr</code> hoặc <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>Full WebDAV endpoint, bao gồm <code>https://</code>.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>Thường dùng <code>Basic</code>; dùng <code>Digest</code> nếu server yêu cầu digest authentication.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>Directory nơi files được lưu. Mặc định là <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-tao-app-password" tabindex="-1">1. Tạo App Password <a class="header-anchor" href="#_1-tao-app-password" aria-label="Permalink to &quot;1. Tạo App Password&quot;">​</a></h3><p>Mở account security settings, tìm application passwords và tạo app password mới.</p><p><img src="'+e+'" alt="Create an app password" loading="lazy"></p><p>Sau khi tạo, copy và lưu app password mới. Thường password này chỉ hiện một lần.</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-đien-webdav-configuration-trong-imgbed" tabindex="-1">2. Điền WebDAV Configuration trong ImgBed <a class="header-anchor" href="#_2-đien-webdav-configuration-trong-imgbed" aria-label="Permalink to &quot;2. Điền WebDAV Configuration trong ImgBed&quot;">​</a></h3><p>Quay lại ImgBed và thêm WebDAV channel:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL do <code>https://fie.nl.tab.digital/</code> cung cấp.</td></tr><tr><td>Username</td><td>WebDAV username của bạn.</td></tr><tr><td>Password</td><td>App password vừa tạo.</td></tr><tr><td>Authentication mode</td><td>Hầu hết trường hợp bắt đầu với <code>Basic</code>.</td></tr><tr><td>Storage directory</td><td>Mặc định là <code>imgbed</code>; cũng có thể dùng custom directory.</td></tr></tbody></table><p><img src="'+n+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="hanh-vi-upload-file-lon" tabindex="-1">Hành vi upload file lớn <a class="header-anchor" href="#hanh-vi-upload-file-lon" aria-label="Permalink to &quot;Hành vi upload file lớn&quot;">​</a></h2><p>WebDAV channel hiện dùng real session-based chunked upload.</p><p>Files nhỏ được upload dưới dạng một complete file. Files lớn hơn 64 MiB sẽ tự động được chia thành chunks khoảng 10 MiB và upload vào remote chunk directory.</p><p>WebDAV service không cần hỗ trợ <code>partial update</code> hoặc offset-based writes. ImgBed không merge chunks thành một large file trên remote server. Thay vào đó, ImgBed lưu chunk manifest và đọc chunks theo thứ tự khi file được request.</p><p>Thực tế:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB hoặc nhỏ hơn</td><td>Normal upload</td><td>Một complete file</td></tr><tr><td>Lớn hơn 64 MiB</td><td>Real session chunked upload</td><td>Một chunk directory chứa nhiều chunk files</td></tr></tbody></table><p>Chunk directory chỉ ảnh hưởng đến remote storage layout. File URL trong ImgBed không đổi. Users vẫn access file bằng link <code>/file/...</code> ban đầu.</p><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><ol><li>Mở Upload Settings.</li><li>Nhấn Add Channel.</li><li>Chọn <code>WebDAV</code>.</li><li>Nhập channel name dễ nhận biết, ví dụ <code>koofr</code>.</li><li>Nhập WebDAV endpoint, ví dụ <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Nhập username và password.</li><li>Giữ authentication mode là <code>Basic</code> theo mặc định.</li><li>Giữ storage directory là <code>imgbed</code>, hoặc đổi sang directory của bạn.</li><li>Nhấn Save.</li><li>Sau khi save, kiểm tra channel card, query capacity nếu có, và upload test file.</li></ol><h2 id="cach-kiem-tra" tabindex="-1">Cách kiểm tra <a class="header-anchor" href="#cach-kiem-tra" aria-label="Permalink to &quot;Cách kiểm tra&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cách kiểm tra</th></tr></thead><tbody><tr><td>Channel card xuất hiện</td><td>Sau khi save, trang Upload Settings cần hiển thị WebDAV channel card.</td></tr><tr><td>Channel enabled</td><td>Switch ở góc trên bên phải card nên ở trạng thái on.</td></tr><tr><td>Credentials đã lưu</td><td>Detail view cần hiển thị Endpoint, username, authentication mode và storage directory.</td></tr><tr><td>Small file upload hoạt động</td><td>Upload test image và xác nhận file xuất hiện trong WebDAV directory.</td></tr><tr><td>Large file rule hoạt động</td><td>Files lớn hơn 64 MiB dùng chunked upload và tạo remote chunk directory.</td></tr><tr><td>Capacity query hoạt động</td><td>Nếu server hỗ trợ capacity information, query sẽ hiển thị used và total capacity.</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="vi-sao-large-webdav-files-tao-chunk-directory" tabindex="-1">Vì sao large WebDAV files tạo chunk directory? <a class="header-anchor" href="#vi-sao-large-webdav-files-tao-chunk-directory" aria-label="Permalink to &quot;Vì sao large WebDAV files tạo chunk directory?&quot;">​</a></h3><p>Đây là storage method hiện tại cho large files.</p><p>Files lớn hơn 64 MiB không được merge thành một remote file lớn. Chúng được lưu dưới dạng chunk directory. ImgBed ghi chunk manifest và trả về complete content bằng cách đọc chunks theo thứ tự.</p><h3 id="large-file-upload-fail-thi-nen-kiem-tra-gi-truoc" tabindex="-1">Large file upload fail thì nên kiểm tra gì trước? <a class="header-anchor" href="#large-file-upload-fail-thi-nen-kiem-tra-gi-truoc" aria-label="Permalink to &quot;Large file upload fail thì nên kiểm tra gì trước?&quot;">​</a></h3><p>Trước hết kiểm tra Endpoint, username, password và storage directory. Sau đó xác nhận WebDAV service cho phép tạo directory, ghi file và đọc file.</p><p>Nếu capacity query fail nhưng small file upload vẫn hoạt động, server có thể đơn giản là không hỗ trợ hoặc giới hạn capacity reporting. Điều đó không nhất thiết có nghĩa upload không dùng được.</p><h3 id="nen-dung-authentication-mode-nao" tabindex="-1">Nên dùng authentication mode nào? <a class="header-anchor" href="#nen-dung-authentication-mode-nao" aria-label="Permalink to &quot;Nên dùng authentication mode nào?&quot;">​</a></h3><p>Bắt đầu với <code>Basic</code>.</p><p>Nếu server yêu cầu digest authentication rõ ràng, dùng <code>Digest</code>.</p><p>Nếu không chắc, dùng automatic negotiation.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chuẩn bị WebDAV endpoint, username và password</span></span>
<span class="line"><span>-&gt; Mở Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Chọn WebDAV</span></span>
<span class="line"><span>-&gt; Nhập Endpoint / username / password</span></span>
<span class="line"><span>-&gt; Giữ authentication mode là Basic theo mặc định</span></span>
<span class="line"><span>-&gt; Giữ storage directory là imgbed theo mặc định</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query capacity</span></span>
<span class="line"><span>-&gt; Upload test file</span></span></code></pre></div>`,45)])])}const v=d(l,[["render",c]]);export{k as __pageData,v as default};
